  "code": "    # Count numerical digits in the entire file name
    digit_count = sum(c.isdigit() for c in file_name)
    if digit_count > 3:
        return 'No'

    # Check exactly one period
    if file_name.count('.') != 1:
        return 'No'

    # Split into base and extension
    base, ext = file_name.split('.')

    # Check base is not empty and starts with alphabetic character
    if not base or not base[0].isalpha():
        return 'No'

    # Check extension is one of the allowed types
    if ext not in ['txt', 'exe', 'dll']:
        return 'No'

